ALTER TABLE webhooks            ADD COLUMN IF NOT EXISTS tenant_id UUID NOT NULL DEFAULT '00000000-0000-0000-0000-000000000001' REFERENCES tenants(id);
ALTER TABLE marketing_campaigns ADD COLUMN IF NOT EXISTS tenant_id UUID NOT NULL DEFAULT '00000000-0000-0000-0000-000000000001' REFERENCES tenants(id);
ALTER TABLE marketing_events    ADD COLUMN IF NOT EXISTS tenant_id UUID NOT NULL DEFAULT '00000000-0000-0000-0000-000000000001' REFERENCES tenants(id);

-- Performance indexes
CREATE INDEX idx_users_tenant         ON users (tenant_id);
CREATE INDEX idx_roles_tenant         ON roles (tenant_id);
CREATE INDEX idx_leads_tenant         ON leads (tenant_id);
CREATE INDEX idx_persons_tenant       ON persons (tenant_id);
CREATE INDEX idx_organizations_tenant ON organizations (tenant_id);
CREATE INDEX idx_activities_tenant    ON activities (tenant_id);
CREATE INDEX idx_quotes_tenant        ON quotes (tenant_id);
CREATE INDEX idx_products_tenant      ON products (tenant_id);
CREATE INDEX idx_warehouses_tenant    ON warehouses (tenant_id);
